        if not isinstance(item, dict):
            continue
        name = str(item.get("name") or "").strip()
        if not name:
            continue
        cookies[name] = str(item.get("value") or "")
    return cookies


def parse_cookie_header(value: str) -> dict[str, str]:
    cookies: dict[str, str] = {}
    for chunk in str(value or "").split(";"):
        part = chunk.strip()
        if not part or "=" not in part:
            continue
        key, val = part.split("=", 1)
        key = key.strip()
        if not key:
            continue
        cookies[key] = val.strip()
    return cookies


def split_header_line(value: str) -> tuple[str, str]:
    raw = str(value or "")
    if ":" not in raw:
        return raw.strip(), ""
    name, header_value = raw.split(":", 1)
    return name.strip(), header_value.strip()


def body_from_text(text: str, content_type: str) -> tuple[str, Any] | None:
    body_text = str(text or "")
    if body_text == "":
        return None
    content_type_lower = content_type.lower()

    if "application/json" in content_type_lower:
        try:
            return ("json", json.loads(body_text))
        except Exception:
            return ("data", body_text)

    if "application/x-www-form-urlencoded" in content_type_lower:
        return ("data", simplify_pairs(parse_qsl(body_text, keep_blank_values=True)))

    stripped = body_text.strip()
    if stripped.startswith("{") or stripped.startswith("["):
        try:
            return ("json", json.loads(stripped))
        except Exception:
            pass
    return ("data", body_text)


def normalize_headers_and_cookies(headers: dict[str, str], cookies: Any = None) -> tuple[dict[str, str], dict[str, str] | str | None]:
    normalized_headers = {str(k): str(v) for k, v in headers.items() if str(k).strip()}
    cookie_value: dict[str, str] | str | None = None
    for name in list(normalized_headers.keys()):
        if name.lower() == "cookie":
            cookie_value = parse_cookie_header(normalized_headers.pop(name))
            break

    if cookies:
        if isinstance(cookies, dict):
            merged = dict(cookie_value or {}) if isinstance(cookie_value, dict) else {}
            for key, value in cookies.items():
                merged[str(key)] = str(value)
            cookie_value = merged
        elif isinstance(cookies, str):
            parsed = parse_cookie_header(cookies)
            if parsed:
                merged = dict(cookie_value or {}) if isinstance(cookie_value, dict) else {}
                merged.update(parsed)
