    if normalized_headers:
        names = {key.lower() for key in normalized_headers}
        if "user-agent" not in names:
            normalized_headers["User-Agent"] = DEFAULT_USER_AGENT
    else:
        normalized_headers = {"User-Agent": DEFAULT_USER_AGENT}

    return normalized_headers, cookie_value


