@dataclass
class Holding:
    symbol: str
    name: str
    quantity: int
    cost_price: float | None
    asset_type: str
    source_path: str
    ledger_ids: list[str]


def request_session() -> requests.Session:
    session = requests.Session()
    session.headers.update({"User-Agent": DEFAULT_USER_AGENT})
    return session


def chromium_ts_to_iso(value: int | float | None) -> str:
    if not value:
        return ""
    try:
        dt = datetime(1601, 1, 1, tzinfo=timezone.utc) + timedelta(microseconds=float(value))
        return dt.astimezone(timezone(timedelta(hours=8))).isoformat()
    except Exception:
        return ""


def ensure_parent(path: Path) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)


def redact_text(value: str, keep: int = 2) -> str:
    value = str(value or "")
    if len(value) <= keep * 2:
        return value
    return f"{value[:keep]}...{value[-keep:]}"


def normalize_code(value: Any, market: Any = None) -> str:
    raw = str(value or "").strip().upper()
    market_raw = str(market or "").strip().upper()
    if not raw or raw == "NAN":
        return ""
    if raw.endswith(".XSHG"):
        return raw.replace(".XSHG", ".SH")
    if raw.endswith(".XSHE"):
        return raw.replace(".XSHE", ".SZ")
    if raw.endswith((".SH", ".SZ", ".HK")):
        return raw
    if raw.startswith("SH") and len(raw) >= 8:
        return f"{raw[2:8]}.SH"
    if raw.startswith("SZ") and len(raw) >= 8:
        return f"{raw[2:8]}.SZ"
    if raw.isdigit() and len(raw) == 6:
        if market_raw in {"HK", "HKG", "116"}:
            return f"{raw}.HK"
        if market_raw in {"SH", "1", "90", "HA", "XSHG"}:
            return f"{raw}.SH"
        if market_raw in {"SZ", "0", "HA2", "XSHE"}:
            return f"{raw}.SZ"
        market_guess = "SH" if raw.startswith(("5", "6", "9")) else "SZ"
        return f"{raw}.{market_guess}"
    if raw.isdigit() and len(raw) == 5:
        return f"{raw}.HK"
    return raw


def infer_asset_type(symbol: str) -> str:
    code = symbol.split(".")[0]
    if code.startswith(("1", "5", "15")):
        return "fund"
    return "stock"


def summarize_holdings(holdings: list[Holding]) -> dict[str, Any]:
    stocks = [h for h in holdings if h.asset_type == "stock" and not h.symbol.endswith(".HK")]
    hk = [h for h in holdings if h.asset_type == "stock" and h.symbol.endswith(".HK")]
    funds = [h for h in holdings if h.asset_type == "fund"]
    return {
        "total": len(holdings),
        "a_stock": len(stocks),
        "hk_stock": len(hk),
        "fund": len(funds),
        "symbols": [h.symbol for h in holdings],
    }


def write_csv(path: Path, holdings: list[Holding]) -> None:
    ensure_parent(path)
    with path.open("w", encoding="utf-8-sig", newline="") as handle:
        writer = csv.DictWriter(
            handle,
            fieldnames=["symbol", "asset_type", "name", "quantity", "cost_price", "source_path", "ledger_ids"],
        )
        writer.writeheader()
        for holding in holdings:
            writer.writerow(
                {
                    "symbol": holding.symbol,
                    "asset_type": holding.asset_type,
                    "name": holding.name,
                    "quantity": holding.quantity,
                    "cost_price": "" if holding.cost_price is None else f"{holding.cost_price:.6f}",
                    "source_path": holding.source_path,
                    "ledger_ids": "|".join(holding.ledger_ids),
                }
            )


def extract_js_urls(html: str) -> list[str]:
    urls = re.findall(r'src="([^"]+\.js)"', html)
    normalized: list[str] = []
    for url in urls:
        normalized.append(f"https:{url}" if url.startswith("//") else url)
    return normalized


def fetch_bundle_text(session: requests.Session, page_url: str) -> tuple[dict[str, Any], str]:
    response = session.get(page_url, timeout=20)
    info = {
        "page_url": page_url,
        "status_code": response.status_code,
        "content_type": response.headers.get("content-type", ""),
        "html_prefix": response.text[:500],
    }
    html = response.text
    js_urls = extract_js_urls(html)
    info["js_urls"] = js_urls
    bundle_url = next((url for url in js_urls if "/static/js/index." in url), "")
    info["bundle_url"] = bundle_url
    bundle_text = ""
    if bundle_url:
        bundle_response = session.get(bundle_url, timeout=30)
        info["bundle_status_code"] = bundle_response.status_code
        info["bundle_content_type"] = bundle_response.headers.get("content-type", "")
        bundle_text = bundle_response.text if bundle_response.ok else ""
    return info, bundle_text


def detect_api_patterns(bundle_text: str) -> dict[str, Any]:
    api_routes = sorted(set(re.findall(r"/caishen_fund/[A-Za-z0-9_./-]+", bundle_text)))
    hints = {route: (route in bundle_text) for route in KNOWN_ENDPOINT_HINTS}
    param_hints: dict[str, dict[str, Any]] = {}

    stock_idx = bundle_text.find('key:"requestStockPosition"')
    if stock_idx != -1:
        snippet = bundle_text[max(0, stock_idx - 200) : stock_idx + 1500]
        param_hints["stock_position"] = {
            "method_name": "requestStockPosition",
            "endpoint": "/caishen_fund/pc/asset/v1/stock_position",
            "params_detected": sorted(set(re.findall(r"manual_id|fund_key|rzrq_fund_key|userid", snippet))),
            "snippet": snippet[:1200],
        }

    hist_idx = bundle_text.find('key:"queryAccountHistory"')
    if hist_idx != -1:
        snippet = bundle_text[max(0, hist_idx - 200) : hist_idx + 1600]
        param_hints["account_history"] = {
            "method_name": "queryAccountHistory",
            "endpoint": "/caishen_fund/pc/account/v2/get_money_history",
            "params_detected": sorted(
                set(
                    re.findall(
                        r"manual_id|fund_key|rzrq_fund_key|fundid|custid|user_id|start_date|end_date|query_list|page|count|sort_type|sort_order|h5id",
                        snippet,
                    )
                )
            ),
            "snippet": snippet[:1200],
        }

    return {
        "api_routes": api_routes,
        "known_endpoint_hits": hints,
        "param_hints": param_hints,
    }


def sqlite_rows(db_path: Path, query: str, params: tuple[Any, ...] = ()) -> list[tuple[Any, ...]]:
    tmp = Path(tempfile.mkstemp(suffix=".sqlite")[1])
    try:
        shutil.copy2(db_path, tmp)
        connection = sqlite3.connect(tmp)
        try:
            cursor = connection.cursor()
            return cursor.execute(query, params).fetchall()
        finally:
            connection.close()
    finally:
        try:
            tmp.unlink()
        except Exception:
            pass


def inspect_history(history_db: Path) -> list[dict[str, Any]]:
    if not history_db.exists():
        return []
    rows = sqlite_rows(
        history_db,
        "select url, title, visit_count, last_visit_time from urls where url like '%tzzb.10jqka.com.cn%' order by last_visit_time desc limit 20",
    )
    results = []
    for url, title, visit_count, last_visit_time in rows:
        redacted_url = re.sub(r"(/myAccount/a/)([^/?#]+)", lambda match: match.group(1) + redact_text(match.group(2)), str(url))
        results.append(
            {
                "url": redacted_url,
                "title": title,
                "visit_count": visit_count,
                "last_visit_time": chromium_ts_to_iso(last_visit_time),
            }
        )
    return results


def inspect_cookies(cookie_db: Path) -> list[dict[str, Any]]:
    if not cookie_db.exists():
        return []
    rows = sqlite_rows(
        cookie_db,
        "select host_key, name, length(value), length(encrypted_value), expires_utc from cookies where host_key like '%10jqka%' or host_key like '%thsi.cn%' or host_key like '%tzzb%' order by host_key, name",
    )
    return [
        {
            "host_key": host_key,
            "name": name,
            "value_len": value_len,
            "encrypted_value_len": encrypted_value_len,
            "expires_at": chromium_ts_to_iso(expires_utc),
        }
        for host_key, name, value_len, encrypted_value_len, expires_utc in rows
    ]


def inspect_local_storage(leveldb_dir: Path) -> dict[str, Any]:
    if not leveldb_dir.exists():
        return {"hits": [], "samples": []}
    needles = [
        b"https://tzzb.10jqka.com.cn",
        b"defaultPositioin|aggregation",
        b"tzzbweb_xcs_homepagelogin",
        b"C6QIQGQ",
    ]
    hits: list[dict[str, Any]] = []
    samples: list[str] = []
    for file_path in sorted(leveldb_dir.glob("*")):
        if not file_path.is_file():
            continue
        try:
            data = file_path.read_bytes()
        except Exception:
            continue
        matched = [needle.decode() for needle in needles if needle in data]
        if not matched:
            continue
        hits.append({"file": file_path.name, "markers": matched})
        if len(samples) >= 4:
            continue
        lowered = data.lower()
        for marker in [b"defaultpositioin|aggregation", b"https://tzzb.10jqka.com.cn", b"tzzbweb_xcs_homepagelogin"]:
            index = lowered.find(marker)
            if index == -1:
                continue
            chunk = data[max(0, index - 120) : index + 260]
            text = "".join(chr(char) if 32 <= char < 127 else "." for char in chunk)
            samples.append(text[:380])
            break
    return {"hits": hits, "samples": samples}


def available_profiles(root: Path) -> list[Path]:
    if not root.exists():
        return []
    profiles = []
    for item in root.iterdir():
        if item.is_dir() and (item.name == "Default" or item.name.startswith("Profile")):
            profiles.append(item)
    return sorted(profiles)


def inspect_browser_artifacts() -> dict[str, Any]:
    result: dict[str, Any] = {}
    for name, root in DEFAULT_BROWSER_ROOTS.items():
        browser_info = {"root": str(root), "exists": root.exists(), "profiles": []}
        for profile in available_profiles(root):
            browser_info["profiles"].append(
                {
                    "profile": profile.name,
                    "history_hits": inspect_history(profile / "History"),
                    "cookie_hits": inspect_cookies(profile / "Cookies"),
                    "local_storage": inspect_local_storage(profile / "Local Storage" / "leveldb"),
                }
            )
        result[name] = browser_info
    return result


def detect_runtime_capabilities() -> dict[str, Any]:
    edge_bin = Path("/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge")
    return {
        "python_modules": {
            "playwright": _module_available("playwright"),
            "pyppeteer": _module_available("pyppeteer"),
            "selenium": _module_available("selenium"),
        },
        "binaries": {
            "microsoft_edge": str(edge_bin) if edge_bin.exists() else "",
        },
    }


def _module_available(name: str) -> bool:
    try:
        __import__(name)
        return True
    except Exception:
        return False


def cmd_scan(args: argparse.Namespace) -> int:
    session = request_session()
    bundle_info, bundle_text = fetch_bundle_text(session, args.page_url)
    api_info = detect_api_patterns(bundle_text)
    browser_info = inspect_browser_artifacts()
    runtime = detect_runtime_capabilities()
    payload = {
        "generated_at": datetime.now(timezone(timedelta(hours=8))).isoformat(),
        "page": bundle_info,
        "api_scan": api_info,
        "browser_artifacts": browser_info,
        "runtime": runtime,
        "conclusion_hint": {
            "has_bundle_api_patterns": bool(api_info["api_routes"]),
            "has_edge_history": bool(browser_info.get("edge", {}).get("profiles")),
            "playwright_python_installed": runtime["python_modules"]["playwright"],
        },
    }
    text = json.dumps(payload, ensure_ascii=False, indent=2)
    if args.out:
        out_path = Path(args.out).expanduser().resolve()
        ensure_parent(out_path)
        out_path.write_text(text, encoding="utf-8")
        print(out_path)
    else:
        print(text)
    return 0


def simplify_pairs(pairs: list[tuple[str, str]]) -> dict[str, Any]:
    result: dict[str, Any] = {}
    for key, value in pairs:
        if key in result:
            existing = result[key]
            if isinstance(existing, list):
                existing.append(value)
            else:
                result[key] = [existing, value]
        else:
            result[key] = value
    return result


def header_items_to_dict(items: Any) -> dict[str, str]:
    headers: dict[str, str] = {}
    if not isinstance(items, list):
        return headers
    for item in items:
        if not isinstance(item, dict):
            continue
        name = str(item.get("name") or "").strip()
        if not name or name.startswith(":"):
            continue
        headers[name] = str(item.get("value") or "")
    return headers


def cookie_items_to_dict(items: Any) -> dict[str, str]:
    cookies: dict[str, str] = {}
    if not isinstance(items, list):
        return cookies
    for item in items:
        if not isinstance(item, dict):
            continue
        name = str(item.get("name") or "").strip()
        if not name:
            continue
        cookies[name] = str(item.get("value") or "")
    return cookies


def parse_cookie_header(value: str) -> dict[str, str]:
    cookies: dict[str, str] = {}
    for chunk in str(value or "").split(";"):
        part = chunk.strip()
        if not part or "=" not in part:
            continue
        key, val = part.split("=", 1)
        key = key.strip()
        if key:
            cookies[key] = val.strip()
    return cookies


def split_header_line(value: str) -> tuple[str, str]:
    raw = str(value or "")
    if ":" not in raw:
        return raw.strip(), ""
    name, header_value = raw.split(":", 1)
    return name.strip(), header_value.strip()


def body_from_text(text: str, content_type: str) -> tuple[str, Any] | None:
    body_text = str(text or "")
    if body_text == "":
        return None
    content_type_lower = content_type.lower()

    if "application/json" in content_type_lower:
        try:
            return ("json", json.loads(body_text))
        except Exception:
            return ("data", body_text)

    if "application/x-www-form-urlencoded" in content_type_lower:
        return ("data", simplify_pairs(parse_qsl(body_text, keep_blank_values=True)))

    stripped = body_text.strip()
    if stripped.startswith("{") or stripped.startswith("["):
        try:
            return ("json", json.loads(stripped))
        except Exception:
            pass
    return ("data", body_text)


def get_header_value(headers: dict[str, str], name: str) -> str:
    target = name.lower()
    for key, value in headers.items():
        if key.lower() == target:
            return value
    return ""


def normalize_headers_and_cookies(
    headers: dict[str, str], cookies: Any = None
) -> tuple[dict[str, str], dict[str, str] | str | None]:
    normalized_headers = {str(key): str(value) for key, value in headers.items() if str(key).strip()}
    cookie_value: dict[str, str] | str | None = None
    for name in list(normalized_headers.keys()):
        if name.lower() == "cookie":
            cookie_value = parse_cookie_header(normalized_headers.pop(name))
            break

    if cookies:
        if isinstance(cookies, dict):
            merged = dict(cookie_value or {}) if isinstance(cookie_value, dict) else {}
            for key, value in cookies.items():
                merged[str(key)] = str(value)
            cookie_value = merged
        elif isinstance(cookies, str):
            parsed = parse_cookie_header(cookies)
            if parsed:
                merged = dict(cookie_value or {}) if isinstance(cookie_value, dict) else {}
                merged.update(parsed)
                cookie_value = merged
            else:
                cookie_value = cookies.strip()

    if not any(key.lower() == "user-agent" for key in normalized_headers):
        normalized_headers["User-Agent"] = DEFAULT_USER_AGENT
    return normalized_headers, cookie_value


def request_spec_summary(spec: dict[str, Any]) -> dict[str, Any]:
    headers = spec.get("headers") or {}
    body_kind = "none"
    if "json" in spec:
        body_kind = "json"
    elif "data" in spec:
        body_kind = "data"
    return {
        "url": spec.get("url", ""),
        "method": spec.get("method", "GET"),
        "header_names": sorted(headers.keys()),
        "cookie_names": sorted((spec.get("cookies") or {}).keys()) if isinstance(spec.get("cookies"), dict) else [],
        "body_kind": body_kind,
        "has_params": "params" in spec,
    }


def write_request_spec(path: Path, spec: dict[str, Any], meta: dict[str, Any]) -> None:
    ensure_parent(path)
    payload = dict(spec)
    payload["__meta__"] = meta
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def load_request_spec(path: Path) -> dict[str, Any]:
    payload = json.loads(path.read_text(encoding="utf-8"))
    if not isinstance(payload, dict):
        raise ValueError("request json 顶层必须是对象")
    payload = dict(payload)
    payload.pop("__meta__", None)
    return payload


def build_cookie_header(cookies: Any) -> str:
    if isinstance(cookies, str):
        return cookies.strip()
    if isinstance(cookies, dict):
        return "; ".join(f"{key}={value}" for key, value in cookies.items())
    return ""


def replay_request(spec: dict[str, Any]) -> requests.Response:
    url = str(spec.get("url") or "").strip()
    if not url:
        raise ValueError("request json 缺少 url")
    method = str(spec.get("method") or "GET").upper()
    headers = {str(key): str(value) for key, value in (spec.get("headers") or {}).items()}
    if not any(key.lower() == "user-agent" for key in headers):
        headers["User-Agent"] = DEFAULT_USER_AGENT
    cookie_header = build_cookie_header(spec.get("cookies"))
    if cookie_header and not any(key.lower() == "cookie" for key in headers):
        headers["Cookie"] = cookie_header
    timeout = int(spec.get("timeout") or 20)

    request_kwargs: dict[str, Any] = {"headers": headers, "timeout": timeout}
    if "params" in spec:
        request_kwargs["params"] = spec["params"]
    if "json" in spec:
        request_kwargs["json"] = spec["json"]
    if "data" in spec:
        request_kwargs["data"] = spec["data"]
    return request_session().request(method, url, **request_kwargs)


def parse_stock_position_payload(payload: Any, request_url: str, request_spec: dict[str, Any]) -> list[Holding]:
    if not isinstance(payload, dict):
        return []
    position = payload.get("position")
    if not isinstance(position, list):
        ex_data = payload.get("ex_data")
        if isinstance(ex_data, dict) and isinstance(ex_data.get("position"), list):
            position = ex_data.get("position")
        else:
            return []

    spec_data = request_spec.get("data") or request_spec.get("json") or {}
    ledger_ids = [
        str(spec_data.get(key) or "").strip()
        for key in ["manual_id", "fund_key", "rzrq_fund_key"]
        if str(spec_data.get(key) or "").strip()
    ]
    holdings: list[Holding] = []
    for item in position:
        if not isinstance(item, dict):
            continue
        symbol = normalize_code(item.get("code") or item.get("stock_code"), item.get("market") or item.get("market_code"))
        if not symbol:
            continue
        qty_raw = item.get("count") or item.get("entry_count") or item.get("qty") or 0
        try:
            quantity = int(float(qty_raw))
        except Exception:
            quantity = 0
        if quantity <= 0:
            continue
        cost_price = None
        for key in ["cost", "entry_price", "cbjg"]:
            if key in item and str(item.get(key) or "").strip():
                value = str(item.get(key)).replace("HK$", "").replace(",", "")
                try:
                    cost_price = float(value)
                except Exception:
                    cost_price = None
                break
        holdings.append(
            Holding(
                symbol=symbol,
                name=str(item.get("name") or item.get("stock_name") or "").strip(),
                quantity=quantity,
                cost_price=cost_price,
                asset_type=infer_asset_type(symbol),
                source_path=request_url,
                ledger_ids=ledger_ids,
            )
        )
    return holdings


def parse_har_entries(payload: dict[str, Any]) -> list[dict[str, Any]]:
    log = payload.get("log")
    entries = log.get("entries") if isinstance(log, dict) else None
    if not isinstance(entries, list):
        raise ValueError("HAR 缺少 log.entries")
    return [entry for entry in entries if isinstance(entry, dict)]


def choose_har_entry(entries: list[dict[str, Any]], url_contains: str, entry_index: int) -> tuple[int, dict[str, Any], int]:
    indexed: list[tuple[int, dict[str, Any], str]] = []
    for idx, entry in enumerate(entries):
        request = entry.get("request") if isinstance(entry, dict) else None
        if not isinstance(request, dict):
            continue
        url = str(request.get("url") or "").strip()
        if url:
            indexed.append((idx, request, url))

    if not indexed:
        raise ValueError("HAR 中没有可用 request 条目")

    if url_contains:
        matches = [item for item in indexed if url_contains in item[2]]
    else:
        hinted = [item for item in indexed if any(hint in item[2] for hint in KNOWN_ENDPOINT_HINTS)]
        matches = hinted or indexed

    if not matches:
        raise ValueError("HAR 中未找到匹配条目；可改用 --url-contains 精确筛选")

    if entry_index >= 0:
        for idx, request, _url in matches:
            if idx == entry_index:
                return idx, request, len(matches)
        raise ValueError(f"HAR 中没有 entry_index={entry_index} 的匹配条目")

    idx, request, _url = matches[0]
    return idx, request, len(matches)


def har_request_to_spec(request: dict[str, Any]) -> dict[str, Any]:
    headers, cookies = normalize_headers_and_cookies(
        header_items_to_dict(request.get("headers")),
        cookie_items_to_dict(request.get("cookies")),
    )
    spec: dict[str, Any] = {
        "url": str(request.get("url") or "").strip(),
        "method": str(request.get("method") or "GET").upper(),
        "headers": headers,
    }
    if cookies:
        spec["cookies"] = cookies

    post_data = request.get("postData")
    if isinstance(post_data, dict):
        content_type = str(post_data.get("mimeType") or get_header_value(headers, "Content-Type") or "")
        body = body_from_text(str(post_data.get("text") or ""), content_type)
        if body is None and isinstance(post_data.get("params"), list):
            pairs = []
            for item in post_data.get("params") or []:
                if not isinstance(item, dict):
                    continue
                name = str(item.get("name") or "").strip()
                if name:
                    pairs.append((name, str(item.get("value") or "")))
            if pairs:
