def normalize_curl_text(text: str) -> str:
    normalized = text.replace("\r\n", "\n")
    normalized = re.sub(r"\\\s*\n", " ", normalized)
    return normalized.strip()


def curl_text_to_spec(text: str) -> dict[str, Any]:
    normalized = normalize_curl_text(text)
    if not normalized:
        raise ValueError("cURL 文本为空")
    tokens = shlex.split(normalized, posix=True)
    if tokens and tokens[0].lower() == "curl":
        tokens = tokens[1:]
    if not tokens:
        raise ValueError("未解析到有效 cURL token")

    headers: dict[str, str] = {}
    cookie_parts: list[str] = []
    data_parts: list[str] = []
    url = ""
    method = ""
    use_get = False
    i = 0
    while i < len(tokens):
        token = tokens[i]

        def next_value() -> str:
            nonlocal i
            if i + 1 >= len(tokens):
                raise ValueError(f"cURL 选项缺少值: {token}")
            i += 1
            return tokens[i]

        if token in {"-X", "--request"}:
            method = next_value()
        elif token.startswith("--request="):
            method = token.split("=", 1)[1]
        elif token.startswith("-X") and token != "-X":
            method = token[2:]
        elif token in {"-H", "--header"}:
            name, value = split_header_line(next_value())
            if name:
                headers[name] = value
        elif token.startswith("--header="):
            name, value = split_header_line(token.split("=", 1)[1])
            if name:
                headers[name] = value
        elif token.startswith("-H") and token != "-H":
            name, value = split_header_line(token[2:])
            if name:
                headers[name] = value
        elif token in {"-b", "--cookie"}:
            cookie_parts.append(next_value())
        elif token.startswith("--cookie="):
            cookie_parts.append(token.split("=", 1)[1])
        elif token.startswith("-b") and token != "-b":
            cookie_parts.append(token[2:])
        elif token in {"-d", "--data", "--data-raw", "--data-binary", "--data-ascii", "--data-urlencode"}:
            data_parts.append(next_value())
        elif any(token.startswith(prefix) for prefix in ["--data=", "--data-raw=", "--data-binary=", "--data-ascii=", "--data-urlencode="]):
            data_parts.append(token.split("=", 1)[1])
        elif token.startswith("-d") and token != "-d":
            data_parts.append(token[2:])
        elif token in {"--url"}:
            url = next_value()
        elif token.startswith("--url="):
            url = token.split("=", 1)[1]
        elif token in {"-A", "--user-agent"}:
            headers["User-Agent"] = next_value()
        elif token.startswith("--user-agent="):
            headers["User-Agent"] = token.split("=", 1)[1]
        elif token.startswith("-A") and token != "-A":
            headers["User-Agent"] = token[2:]
        elif token in {"-e", "--referer", "--referrer"}:
            headers["Referer"] = next_value()
        elif token.startswith("--referer=") or token.startswith("--referrer="):
            headers["Referer"] = token.split("=", 1)[1]
        elif token.startswith("-e") and token != "-e":
            headers["Referer"] = token[2:]
        elif token in {"-G", "--get"}:
            use_get = True
        elif token.startswith("http://") or token.startswith("https://"):
            url = token
        elif token in {"--compressed", "--location", "-L", "--insecure", "-k", "-s", "--silent", "-i", "--include", "--http1.1", "--http2", "--path-as-is", "--globoff", "--verbose", "-v"}:
            pass
        i += 1

    if not url:
        raise ValueError("cURL 中缺少 URL")

    headers, cookies = normalize_headers_and_cookies(headers, "; ".join(cookie_parts) if cookie_parts else None)
    method = method.upper() if method else ("GET" if not data_parts else "POST")
    if use_get:
        method = "GET"

    spec: dict[str, Any] = {"url": url, "method": method, "headers": headers}
    if cookies:
        spec["cookies"] = cookies

    if data_parts:
        body_text = "&".join(part for part in data_parts if part is not None)
        if use_get:
            spec["params"] = simplify_pairs(parse_qsl(body_text, keep_blank_values=True))
        else:
            body = body_from_text(body_text, get_header_value(headers, "Content-Type"))
            if body is not None:
                spec[body[0]] = body[1]
    return spec


