                                "source_path": holding.source_path,
                                "ledger_ids": holding.ledger_ids,
                            }
                            for holding in holdings
                        ],
                    },
                    ensure_ascii=False,
                    indent=2,
                ),
                encoding="utf-8",
            )
            result["normalized_csv"] = str(csv_path)
            result["normalized_json"] = str(normalized_json_path)
            result["summary"] = summarize_holdings(holdings)

    print(json.dumps(result, ensure_ascii=False, indent=2))
    return 0 if response.ok else 1


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="探测/转换/回放同花顺投资账本网页 API 请求")
    sub = parser.add_subparsers(dest="command", required=True)

    scan_parser = sub.add_parser("scan", help="扫描网页 bundle、浏览器 cookie/localStorage/history 痕迹")
    scan_parser.add_argument("--page-url", default=DEFAULT_PAGE_URL, help="投资账本页面 URL")
    scan_parser.add_argument("--out", default="", help="输出 JSON 文件")
    scan_parser.set_defaults(func=cmd_scan)

    convert_har_parser = sub.add_parser("convert-har", help="把 HAR 中的请求条目转换成 request-json")
    convert_har_parser.add_argument("--har", required=True, help="HAR 文件路径")
    convert_har_parser.add_argument("--out", required=True, help="输出 request-json 文件")
    convert_har_parser.add_argument("--url-contains", default="", help="仅选择 URL 包含该片段的条目")
    convert_har_parser.add_argument("--entry-index", type=int, default=-1, help="显式指定 HAR entry 下标")
    convert_har_parser.set_defaults(func=cmd_convert_har)

    convert_curl_parser = sub.add_parser("convert-curl", help="把 cURL 文本转换成 request-json")
    curl_source = convert_curl_parser.add_mutually_exclusive_group(required=True)
    curl_source.add_argument("--curl", default="", help="直接传入 cURL 文本")
    curl_source.add_argument("--curl-file", default="", help="包含 cURL 文本的文件")
    convert_curl_parser.add_argument("--out", required=True, help="输出 request-json 文件")
    convert_curl_parser.set_defaults(func=cmd_convert_curl)

    replay_parser = sub.add_parser("replay", help="用 request-json 回放 API，并尽量归一化持仓")
    replay_parser.add_argument("--request-json", required=True, help="请求定义 JSON，包含 url/method/headers/cookies/data/json")
    replay_parser.add_argument("--out-dir", default=".", help="输出目录")
    replay_parser.add_argument("--csv-name", default="ths_selected_holdings.csv", help="归一化 CSV 文件名")
    replay_parser.add_argument("--json-name", default="ths_selected_holdings.json", help="归一化 JSON 文件名")
    replay_parser.add_argument("--dry-run", action="store_true", help="只校验 request-json 与预览，不实际发请求")
    replay_parser.set_defaults(func=cmd_replay)

    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()
    return int(args.func(args))


if __name__ == "__main__":
    raise SystemExit(main())
