                    "history_hits": inspect_history(profile / "History"),
                    "cookie_hits": inspect_cookies(profile / "Cookies"),
                    "local_storage": inspect_local_storage(profile / "Local Storage" / "leveldb"),
                }
            )
        result[name] = browser_info
    return result


def detect_runtime_capabilities() -> dict[str, Any]:
    edge_bin = Path("/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge")
    return {
        "python_modules": {
            "playwright": _module_available("playwright"),
            "pyppeteer": _module_available("pyppeteer"),
            "selenium": _module_available("selenium"),
        },
        "binaries": {
            "microsoft_edge": str(edge_bin) if edge_bin.exists() else "",
        },
    }


def _module_available(name: str) -> bool:
    try:
        __import__(name)
        return True
    except Exception:
        return False


def cmd_scan(args: argparse.Namespace) -> int:
    session = request_session()
    bundle_info, bundle_text = fetch_bundle_text(session, args.page_url)
    api_info = detect_api_patterns(bundle_text)
    browser_info = inspect_browser_artifacts()
    runtime = detect_runtime_capabilities()
    payload = {
        "generated_at": datetime.now(timezone(timedelta(hours=8))).isoformat(),
        "page": bundle_info,
        "api_scan": api_info,
        "browser_artifacts": browser_info,
        "runtime": runtime,
        "conclusion_hint": {
            "has_bundle_api_patterns": bool(api_info["api_routes"]),
            "has_edge_history": bool(browser_info.get("edge", {}).get("profiles")),
            "playwright_python_installed": runtime["python_modules"]["playwright"],
        },
    }
    text = json.dumps(payload, ensure_ascii=False, indent=2)
    if args.out:
        out_path = Path(args.out).expanduser().resolve()
        ensure_parent(out_path)
        out_path.write_text(text, encoding="utf-8")
        print(out_path)
    else:
        print(text)
    return 0


def simplify_pairs(pairs: list[tuple[str, str]]) -> dict[str, Any]:
    result: dict[str, Any] = {}
    for key, value in pairs:
        if key in result:
            existing = result[key]
            if isinstance(existing, list):
                existing.append(value)
            else:
                result[key] = [existing, value]
        else:
            result[key] = value
    return result


def header_items_to_dict(items: Any) -> dict[str, str]:
    headers: dict[str, str] = {}
    if not isinstance(items, list):
        return headers
    for item in items:
        if not isinstance(item, dict):
            continue
        name = str(item.get("name") or "").strip()
        if not name or name.startswith(":"):
            continue
        headers[name] = str(item.get("value") or "")
    return headers


def cookie_items_to_dict(items: Any) -> dict[str, str]:
    cookies: dict[str, str] = {}
    if not isinstance(items, list):
        return cookies
    for item in items:
        if not isinstance(item, dict):
            continue
        name = str(item.get("name") or "").strip()
        if not name:
            continue
        cookies[name] = str(item.get("value") or "")
    return cookies


def parse_cookie_header(value: str) -> dict[str, str]:
    cookies: dict[str, str] = {}
    for chunk in str(value or "").split(";"):
        part = chunk.strip()
        if not part or "=" not in part:
            continue
        key, val = part.split("=", 1)
        key = key.strip()
        if key:
            cookies[key] = val.strip()
    return cookies


def split_header_line(value: str) -> tuple[str, str]:
    raw = str(value or "")
    if ":" not in raw:
        return raw.strip(), ""
    name, header_value = raw.split(":", 1)
    return name.strip(), header_value.strip()


def body_from_text(text: str, content_type: str) -> tuple[str, Any] | None:
    body_text = str(text or "")
    if body_text == "":
        return None
    content_type_lower = content_type.lower()

    if "application/json" in content_type_lower:
        try:
            return ("json", json.loads(body_text))
        except Exception:
            return ("data", body_text)

    if "application/x-www-form-urlencoded" in content_type_lower:
        return ("data", simplify_pairs(parse_qsl(body_text, keep_blank_values=True)))

    stripped = body_text.strip()
    if stripped.startswith("{") or stripped.startswith("["):
        try:
            return ("json", json.loads(stripped))
        except Exception:
            pass
    return ("data", body_text)


def get_header_value(headers: dict[str, str], name: str) -> str:
    target = name.lower()
    for key, value in headers.items():
        if key.lower() == target:
            return value
    return ""


def normalize_headers_and_cookies(
    headers: dict[str, str], cookies: Any = None
) -> tuple[dict[str, str], dict[str, str] | str | None]:
    normalized_headers = {str(key): str(value) for key, value in headers.items() if str(key).strip()}
    cookie_value: dict[str, str] | str | None = None
    for name in list(normalized_headers.keys()):
        if name.lower() == "cookie":
            cookie_value = parse_cookie_header(normalized_headers.pop(name))
            break

    if cookies:
        if isinstance(cookies, dict):
            merged = dict(cookie_value or {}) if isinstance(cookie_value, dict) else {}
            for key, value in cookies.items():
                merged[str(key)] = str(value)
            cookie_value = merged
        elif isinstance(cookies, str):
            parsed = parse_cookie_header(cookies)
            if parsed:
                merged = dict(cookie_value or {}) if isinstance(cookie_value, dict) else {}
                merged.update(parsed)
                cookie_value = merged
            else:
                cookie_value = cookies.strip()

    if not any(key.lower() == "user-agent" for key in normalized_headers):
        normalized_headers["User-Agent"] = DEFAULT_USER_AGENT
    return normalized_headers, cookie_value


def request_spec_summary(spec: dict[str, Any]) -> dict[str, Any]:
    headers = spec.get("headers") or {}
    body_kind = "none"
    if "json" in spec:
        body_kind = "json"
    elif "data" in spec:
        body_kind = "data"
    return {
        "url": spec.get("url", ""),
        "method": spec.get("method", "GET"),
        "header_names": sorted(headers.keys()),
        "cookie_names": sorted((spec.get("cookies") or {}).keys()) if isinstance(spec.get("cookies"), dict) else [],
        "body_kind": body_kind,
        "has_params": "params" in spec,
    }


def write_request_spec(path: Path, spec: dict[str, Any], meta: dict[str, Any]) -> None:
    ensure_parent(path)
    payload = dict(spec)
    payload["__meta__"] = meta
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def load_request_spec(path: Path) -> dict[str, Any]:
    payload = json.loads(path.read_text(encoding="utf-8"))
    if not isinstance(payload, dict):
        raise ValueError("request json 顶层必须是对象")
    payload = dict(payload)
    payload.pop("__meta__", None)
    return payload


def build_cookie_header(cookies: Any) -> str:
    if isinstance(cookies, str):
        return cookies.strip()
    if isinstance(cookies, dict):
        return "; ".join(f"{key}={value}" for key, value in cookies.items())
    return ""


def replay_request(spec: dict[str, Any]) -> requests.Response:
    url = str(spec.get("url") or "").strip()
    if not url:
        raise ValueError("request json 缺少 url")
    method = str(spec.get("method") or "GET").upper()
    headers = {str(key): str(value) for key, value in (spec.get("headers") or {}).items()}
    if not any(key.lower() == "user-agent" for key in headers):
        headers["User-Agent"] = DEFAULT_USER_AGENT
    cookie_header = build_cookie_header(spec.get("cookies"))
    if cookie_header and not any(key.lower() == "cookie" for key in headers):
        headers["Cookie"] = cookie_header
    timeout = int(spec.get("timeout") or 20)

    request_kwargs: dict[str, Any] = {"headers": headers, "timeout": timeout}
    if "params" in spec:
        request_kwargs["params"] = spec["params"]
    if "json" in spec:
        request_kwargs["json"] = spec["json"]
    if "data" in spec:
        request_kwargs["data"] = spec["data"]
    return request_session().request(method, url, **request_kwargs)


def parse_stock_position_payload(payload: Any, request_url: str, request_spec: dict[str, Any]) -> list[Holding]:
    if not isinstance(payload, dict):
        return []
    position = payload.get("position")
    if not isinstance(position, list):
        ex_data = payload.get("ex_data")
        if isinstance(ex_data, dict) and isinstance(ex_data.get("position"), list):
            position = ex_data.get("position")
        else:
            return []

    spec_data = request_spec.get("data") or request_spec.get("json") or {}
    ledger_ids = [
        str(spec_data.get(key) or "").strip()
        for key in ["manual_id", "fund_key", "rzrq_fund_key"]
        if str(spec_data.get(key) or "").strip()
    ]
    holdings: list[Holding] = []
    for item in position:
        if not isinstance(item, dict):
            continue
        symbol = normalize_code(item.get("code") or item.get("stock_code"), item.get("market") or item.get("market_code"))
        if not symbol:
            continue
        qty_raw = item.get("count") or item.get("entry_count") or item.get("qty") or 0
        try:
            quantity = int(float(qty_raw))
        except Exception:
            quantity = 0
        if quantity <= 0:
            continue
        cost_price = None
        for key in ["cost", "entry_price", "cbjg"]:
            if key in item and str(item.get(key) or "").strip():
                value = str(item.get(key)).replace("HK$", "").replace(",", "")
                try:
                    cost_price = float(value)
                except Exception:
                    cost_price = None
                break
        holdings.append(
            Holding(
                symbol=symbol,
                name=str(item.get("name") or item.get("stock_name") or "").strip(),
                quantity=quantity,
                cost_price=cost_price,
                asset_type=infer_asset_type(symbol),
                source_path=request_url,
                ledger_ids=ledger_ids,
            )
        )
    return holdings


def parse_har_entries(payload: dict[str, Any]) -> list[dict[str, Any]]:
    log = payload.get("log")
    entries = log.get("entries") if isinstance(log, dict) else None
    if not isinstance(entries, list):
        raise ValueError("HAR 缺少 log.entries")
    return [entry for entry in entries if isinstance(entry, dict)]


def choose_har_entry(entries: list[dict[str, Any]], url_contains: str, entry_index: int) -> tuple[int, dict[str, Any], int]:
    indexed: list[tuple[int, dict[str, Any], str]] = []
    for idx, entry in enumerate(entries):
        request = entry.get("request") if isinstance(entry, dict) else None
        if not isinstance(request, dict):
            continue
        url = str(request.get("url") or "").strip()
        if url:
            indexed.append((idx, request, url))

    if not indexed:
        raise ValueError("HAR 中没有可用 request 条目")

    if url_contains:
        matches = [item for item in indexed if url_contains in item[2]]
    else:
        hinted = [item for item in indexed if any(hint in item[2] for hint in KNOWN_ENDPOINT_HINTS)]
        matches = hinted or indexed

    if not matches:
        raise ValueError("HAR 中未找到匹配条目；可改用 --url-contains 精确筛选")

    if entry_index >= 0:
        for idx, request, _url in matches:
            if idx == entry_index:
                return idx, request, len(matches)
        raise ValueError(f"HAR 中没有 entry_index={entry_index} 的匹配条目")

    idx, request, _url = matches[0]
    return idx, request, len(matches)


def har_request_to_spec(request: dict[str, Any]) -> dict[str, Any]:
    headers, cookies = normalize_headers_and_cookies(
        header_items_to_dict(request.get("headers")),
        cookie_items_to_dict(request.get("cookies")),
    )
    spec: dict[str, Any] = {
        "url": str(request.get("url") or "").strip(),
        "method": str(request.get("method") or "GET").upper(),
        "headers": headers,
    }
    if cookies:
        spec["cookies"] = cookies

    post_data = request.get("postData")
    if isinstance(post_data, dict):
        content_type = str(post_data.get("mimeType") or get_header_value(headers, "Content-Type") or "")
        body = body_from_text(str(post_data.get("text") or ""), content_type)
        if body is None and isinstance(post_data.get("params"), list):
            pairs = []
            for item in post_data.get("params") or []:
                if not isinstance(item, dict):
                    continue
                name = str(item.get("name") or "").strip()
                if name:
                    pairs.append((name, str(item.get("value") or "")))
            if pairs:
                body = ("data", simplify_pairs(pairs))
        if body is not None:
            spec[body[0]] = body[1]
    return spec


def cmd_convert_har(args: argparse.Namespace) -> int:
    har_path = Path(args.har).expanduser().resolve()
    payload = json.loads(har_path.read_text(encoding="utf-8"))
    if not isinstance(payload, dict):
        raise ValueError("HAR 顶层必须是对象")
    entries = parse_har_entries(payload)
    selected_index, request, candidate_count = choose_har_entry(entries, args.url_contains, args.entry_index)
    spec = har_request_to_spec(request)
    out_path = Path(args.out).expanduser().resolve()
    meta = {
        "converted_from": "har",
        "source_path": str(har_path),
        "selected_entry_index": selected_index,
        "candidate_count": candidate_count,
        "selected_url": spec.get("url", ""),
    }
    write_request_spec(out_path, spec, meta)
    print(
        json.dumps(
            {
                "out": str(out_path),
                "meta": meta,
                "summary": request_spec_summary(spec),
            },
            ensure_ascii=False,
            indent=2,
        )
    )
    return 0


def normalize_curl_text(text: str) -> str:
    normalized = text.replace("\r\n", "\n")
    normalized = re.sub(r"\\\s*\n", " ", normalized)
    return normalized.strip()


def curl_text_to_spec(text: str) -> dict[str, Any]:
    normalized = normalize_curl_text(text)
    if not normalized:
        raise ValueError("cURL 文本为空")
    tokens = shlex.split(normalized, posix=True)
    if tokens and tokens[0].lower() == "curl":
        tokens = tokens[1:]
    if not tokens:
        raise ValueError("未解析到有效 cURL token")

    headers: dict[str, str] = {}
    cookie_parts: list[str] = []
    data_parts: list[str] = []
    url = ""
    method = ""
    use_get = False
    i = 0
    while i < len(tokens):
        token = tokens[i]

        def next_value() -> str:
            nonlocal i
            if i + 1 >= len(tokens):
                raise ValueError(f"cURL 选项缺少值: {token}")
            i += 1
            return tokens[i]

        if token in {"-X", "--request"}:
            method = next_value()
        elif token.startswith("--request="):
            method = token.split("=", 1)[1]
        elif token.startswith("-X") and token != "-X":
            method = token[2:]
        elif token in {"-H", "--header"}:
            name, value = split_header_line(next_value())
            if name:
                headers[name] = value
        elif token.startswith("--header="):
            name, value = split_header_line(token.split("=", 1)[1])
            if name:
                headers[name] = value
        elif token.startswith("-H") and token != "-H":
            name, value = split_header_line(token[2:])
            if name:
                headers[name] = value
        elif token in {"-b", "--cookie"}:
            cookie_parts.append(next_value())
        elif token.startswith("--cookie="):
            cookie_parts.append(token.split("=", 1)[1])
        elif token.startswith("-b") and token != "-b":
            cookie_parts.append(token[2:])
        elif token in {"-d", "--data", "--data-raw", "--data-binary", "--data-ascii", "--data-urlencode"}:
            data_parts.append(next_value())
        elif any(token.startswith(prefix) for prefix in ["--data=", "--data-raw=", "--data-binary=", "--data-ascii=", "--data-urlencode="]):
            data_parts.append(token.split("=", 1)[1])
        elif token.startswith("-d") and token != "-d":
            data_parts.append(token[2:])
        elif token in {"--url"}:
            url = next_value()
        elif token.startswith("--url="):
            url = token.split("=", 1)[1]
        elif token in {"-A", "--user-agent"}:
            headers["User-Agent"] = next_value()
        elif token.startswith("--user-agent="):
            headers["User-Agent"] = token.split("=", 1)[1]
        elif token.startswith("-A") and token != "-A":
            headers["User-Agent"] = token[2:]
        elif token in {"-e", "--referer", "--referrer"}:
            headers["Referer"] = next_value()
        elif token.startswith("--referer=") or token.startswith("--referrer="):
            headers["Referer"] = token.split("=", 1)[1]
        elif token.startswith("-e") and token != "-e":
            headers["Referer"] = token[2:]
        elif token in {"-G", "--get"}:
            use_get = True
        elif token.startswith("http://") or token.startswith("https://"):
            url = token
        elif token in {"--compressed", "--location", "-L", "--insecure", "-k", "-s", "--silent", "-i", "--include", "--http1.1", "--http2", "--path-as-is", "--globoff", "--verbose", "-v"}:
            pass
        i += 1

    if not url:
        raise ValueError("cURL 中缺少 URL")

    headers, cookies = normalize_headers_and_cookies(headers, "; ".join(cookie_parts) if cookie_parts else None)
    method = method.upper() if method else ("GET" if not data_parts else "POST")
    if use_get:
        method = "GET"

    spec: dict[str, Any] = {"url": url, "method": method, "headers": headers}
    if cookies:
        spec["cookies"] = cookies

    if data_parts:
        body_text = "&".join(part for part in data_parts if part is not None)
        if use_get:
            spec["params"] = simplify_pairs(parse_qsl(body_text, keep_blank_values=True))
        else:
            body = body_from_text(body_text, get_header_value(headers, "Content-Type"))
            if body is not None:
                spec[body[0]] = body[1]
    return spec


def cmd_convert_curl(args: argparse.Namespace) -> int:
    if args.curl_file:
        source_path = Path(args.curl_file).expanduser().resolve()
        curl_text = source_path.read_text(encoding="utf-8")
        source_label = str(source_path)
    else:
        curl_text = str(args.curl or "")
        source_label = "<inline>"
    spec = curl_text_to_spec(curl_text)
    out_path = Path(args.out).expanduser().resolve()
    meta = {
        "converted_from": "curl",
        "source_path": source_label,
        "selected_url": spec.get("url", ""),
    }
    write_request_spec(out_path, spec, meta)
    print(
        json.dumps(
            {
                "out": str(out_path),
                "meta": meta,
                "summary": request_spec_summary(spec),
            },
            ensure_ascii=False,
            indent=2,
        )
    )
    return 0


def cmd_replay(args: argparse.Namespace) -> int:
    request_path = Path(args.request_json).expanduser().resolve()
    spec = load_request_spec(request_path)
    out_dir = Path(args.out_dir).expanduser().resolve()
    out_dir.mkdir(parents=True, exist_ok=True)

    if args.dry_run:
        preview_path = out_dir / "tzzb_request_preview.json"
        preview_path.write_text(json.dumps(spec, ensure_ascii=False, indent=2), encoding="utf-8")
        print(
            json.dumps(
                {
                    "dry_run": True,
                    "request_json": str(request_path),
                    "request_preview": str(preview_path),
                    "summary": request_spec_summary(spec),
                },
                ensure_ascii=False,
                indent=2,
            )
        )
        return 0

    response = replay_request(spec)
    raw_path = out_dir / "tzzb_raw_response.txt"
    raw_path.write_text(response.text, encoding="utf-8")

    result: dict[str, Any] = {
        "status_code": response.status_code,
        "content_type": response.headers.get("content-type", ""),
        "url": response.url,
        "raw_response": str(raw_path),
    }

    parsed_json: Any = None
    try:
        parsed_json = response.json()
    except Exception:
        parsed_json = None

    if parsed_json is not None:
        json_path = out_dir / "tzzb_raw_response.json"
        json_path.write_text(json.dumps(parsed_json, ensure_ascii=False, indent=2), encoding="utf-8")
        result["raw_json"] = str(json_path)
        holdings = parse_stock_position_payload(parsed_json, response.url, spec)
        if holdings:
            csv_path = out_dir / args.csv_name
            normalized_json_path = out_dir / args.json_name
            write_csv(csv_path, holdings)
            normalized_json_path.write_text(
                json.dumps(
                    {
                        "source": "tzzb_web_stock_position_api",
                        "request_json": str(request_path),
                        "request_url": response.url,
                        "status_code": response.status_code,
                        "summary": summarize_holdings(holdings),
                        "holdings": [
                            {
                                "symbol": holding.symbol,
                                "asset_type": holding.asset_type,
                                "name": holding.name,
                                "quantity": holding.quantity,
                                "cost_price": holding.cost_price,
                                "source_path": holding.source_path,
                                "ledger_ids": holding.ledger_ids,
                            }
                            for holding in holdings
                        ],
                    },
                    ensure_ascii=False,
                    indent=2,
                ),
                encoding="utf-8",
            )
            result["normalized_csv"] = str(csv_path)
            result["normalized_json"] = str(normalized_json_path)
            result["summary"] = summarize_holdings(holdings)

    print(json.dumps(result, ensure_ascii=False, indent=2))
    return 0 if response.ok else 1


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="探测/转换/回放同花顺投资账本网页 API 请求")
    sub = parser.add_subparsers(dest="command", required=True)

    scan_parser = sub.add_parser("scan", help="扫描网页 bundle、浏览器 cookie/localStorage/history 痕迹")
    scan_parser.add_argument("--page-url", default=DEFAULT_PAGE_URL, help="投资账本页面 URL")
    scan_parser.add_argument("--out", default="", help="输出 JSON 文件")
    scan_parser.set_defaults(func=cmd_scan)

    convert_har_parser = sub.add_parser("convert-har", help="把 HAR 中的请求条目转换成 request-json")
    convert_har_parser.add_argument("--har", required=True, help="HAR 文件路径")
    convert_har_parser.add_argument("--out", required=True, help="输出 request-json 文件")
    convert_har_parser.add_argument("--url-contains", default="", help="仅选择 URL 包含该片段的条目")
    convert_har_parser.add_argument("--entry-index", type=int, default=-1, help="显式指定 HAR entry 下标")
    convert_har_parser.set_defaults(func=cmd_convert_har)

    convert_curl_parser = sub.add_parser("convert-curl", help="把 cURL 文本转换成 request-json")
    curl_source = convert_curl_parser.add_mutually_exclusive_group(required=True)
    curl_source.add_argument("--curl", default="", help="直接传入 cURL 文本")
    curl_source.add_argument("--curl-file", default="", help="包含 cURL 文本的文件")
    convert_curl_parser.add_argument("--out", required=True, help="输出 request-json 文件")
    convert_curl_parser.set_defaults(func=cmd_convert_curl)

    replay_parser = sub.add_parser("replay", help="用 request-json 回放 API，并尽量归一化持仓")
    replay_parser.add_argument("--request-json", required=True, help="请求定义 JSON，包含 url/method/headers/cookies/data/json")
    replay_parser.add_argument("--out-dir", default=".", help="输出目录")
    replay_parser.add_argument("--csv-name", default="ths_selected_holdings.csv", help="归一化 CSV 文件名")
    replay_parser.add_argument("--json-name", default="ths_selected_holdings.json", help="归一化 JSON 文件名")
    replay_parser.add_argument("--dry-run", action="store_true", help="只校验 request-json 与预览，不实际发请求")
